+function estimateMessageCharsCached(msg: AgentMessage, cache: MessageCharEstimateCache): number {
+  const hit = cache.get(msg);
+  if (hit !== undefined) {
+    return hit;
+  }
+  const estimated = estimateMessageChars(msg);
+  cache.set(msg, estimated);
+  return estimated;
